/**
 * User notification preferences model.
 *
 * Supports per-channel notification preferences (email, SMS, webhook).
 * Each channel has its own enabled flag and per-category subscription map.
 *
 * DECISION CHANGE (Agent 9): The original model (Agent 3) assumed email was
 * the only notification channel. With SMS added (Agent 8) and webhook already
 * available (Agent 6), this model has been refactored to support per-channel
 * preferences. A generic `ChannelPreferences` interface captures the shared
 * structure, with `EmailPreferences` extending it with email-specific fields
 * (frequency). Backward compatibility is preserved: existing code that reads
 * `prefs.email` continues to work unchanged.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/** How often the user wants to receive email notifications. */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest' | 'none';

/**
 * Base per-channel notification preferences.
 * Every channel shares these fields.
 */
export interface ChannelPreferences {
  /** Whether notifications on this channel are enabled at all. */
  enabled: boolean;
  /** Per-category subscription flags. True = subscribed, false = unsubscribed. */
  categories: Record<NotificationType, boolean>;
}

/**
 * Email-specific notification preferences.
 * Extends ChannelPreferences with email-only fields.
 */
export interface EmailPreferences extends ChannelPreferences {
  /** Delivery frequency for non-critical emails. */
  frequency: EmailFrequency;
}

/**
 * SMS-specific notification preferences.
 * Extends ChannelPreferences with SMS-only fields.
 */
export interface SmsPreferences extends ChannelPreferences {
  /** The user's SMS-capable phone number. */
  phoneNumber?: string;
}

/**
 * Webhook-specific notification preferences.
 * Extends ChannelPreferences with webhook-only fields.
 */
export interface WebhookPreferences extends ChannelPreferences {
  /** The webhook URL to deliver to. */
  url?: string;
}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  /** Unique preferences ID. */
  id: string;
  /** The user ID these preferences belong to. */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** SMS notification settings. */
  sms: SmsPreferences;
  /** Webhook notification settings. */
  webhook: WebhookPreferences;
  /** When preferences were created. */
  createdAt: Date;
  /** When preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional — only provided fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categories?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating SMS preferences. All fields optional — only provided fields are changed.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  phoneNumber?: string;
  categories?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating webhook preferences. All fields optional — only provided fields are changed.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  url?: string;
  categories?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Union of all channel update inputs, keyed by channel name.
 */
export type UpdateChannelPreferencesInput = {
  email: UpdateEmailPreferencesInput;
  sms: UpdateSmsPreferencesInput;
  webhook: UpdateWebhookPreferencesInput;
};

/** Default category flags — all enabled. */
function getDefaultCategories(): Record<NotificationType, boolean> {
  return {
    order_confirmation: true,
    order_status_update: true,
    welcome: true,
    account_updated: true,
  };
}

/**
 * Returns the default email preferences for a new user.
 * All categories enabled, immediate delivery.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: getDefaultCategories(),
  };
}

/**
 * Returns the default SMS preferences for a new user.
 * SMS is disabled by default — users must opt in.
 */
export function getDefaultSmsPreferences(): SmsPreferences {
  return {
    enabled: false,
    categories: getDefaultCategories(),
  };
}

/**
 * Returns the default webhook preferences for a new user.
 * Webhook is disabled by default — users must opt in and provide a URL.
 */
export function getDefaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: false,
    categories: getDefaultCategories(),
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Each user has at most one preferences record.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import { getDefaultSmsPreferences, getDefaultWebhookPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string),
      sms: record['sms'] ? JSON.parse(record['sms'] as string) : getDefaultSmsPreferences(),
      webhook: record['webhook'] ? JSON.parse(record['webhook'] as string) : getDefaultWebhookPreferences(),
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and exposes a
 * generic shouldSend(channel, type) check for the NotificationService
 * to determine whether a notification should be delivered.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 *
 * Depends on:
 * - PreferencesRepository for persistence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
  ChannelPreferences,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  getDefaultEmailPreferences,
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const now = new Date();
    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: getDefaultEmailPreferences(),
      sms: getDefaultSmsPreferences(),
      webhook: getDefaultWebhookPreferences(),
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(prefs);
    this.logger.info(`Created default preferences for user: ${userId}`);
    return prefs;
  }

  /**
   * Update email preferences for a user. Creates defaults first if none exist.
   * Only provided fields in the input are changed.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedEmail = { ...current.email };

    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.categories !== undefined) {
      updatedEmail.categories = { ...updatedEmail.categories, ...input.categories };
    }

    const updated = this.repository.update(current.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated email preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Update SMS preferences for a user. Creates defaults first if none exist.
   * Only provided fields in the input are changed.
   */
  updateSmsPreferences(userId: string, input: UpdateSmsPreferencesInput): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedSms = { ...current.sms };

    if (input.enabled !== undefined) {
      updatedSms.enabled = input.enabled;
    }
    if (input.phoneNumber !== undefined) {
      updatedSms.phoneNumber = input.phoneNumber;
    }
    if (input.categories !== undefined) {
      updatedSms.categories = { ...updatedSms.categories, ...input.categories };
    }

    const updated = this.repository.update(current.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated SMS preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Update webhook preferences for a user. Creates defaults first if none exist.
   * Only provided fields in the input are changed.
   */
  updateWebhookPreferences(userId: string, input: UpdateWebhookPreferencesInput): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedWebhook = { ...current.webhook };

    if (input.enabled !== undefined) {
      updatedWebhook.enabled = input.enabled;
    }
    if (input.url !== undefined) {
      updatedWebhook.url = input.url;
    }
    if (input.categories !== undefined) {
      updatedWebhook.categories = { ...updatedWebhook.categories, ...input.categories };
    }

    const updated = this.repository.update(current.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated webhook preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification of the given type should be sent to a user via email.
   *
   * Returns true if:
   * - The user has no preferences (defaults allow all)
   * - Email is enabled AND the specific category is subscribed
   *
   * Backward-compatible: delegates to the generic shouldSend().
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, 'email', notificationType);
  }

  /**
   * Generic check: should a notification of the given type be sent to a user on the given channel?
   *
   * Returns true if:
   * - The user has no preferences (defaults apply — email enabled, SMS/webhook disabled)
   * - The channel is enabled AND the specific category is subscribed
   */
  shouldSend(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No preferences stored — use channel defaults
    if (!prefs) {
      // Email defaults to enabled, SMS and webhook default to disabled
      if (channel === 'email') {
        return true;
      }
      return false;
    }

    const channelPrefs = this.getChannelPreferences(prefs, channel);
    if (!channelPrefs) {
      return false;
    }

    // Channel globally disabled
    if (!channelPrefs.enabled) {
      return false;
    }

    // Check category-level subscription
    return channelPrefs.categories[notificationType] !== false;
  }

  /**
   * Get the ChannelPreferences for a given channel from user preferences.
   */
  private getChannelPreferences(prefs: UserPreferences, channel: NotificationChannel): ChannelPreferences | undefined {
    switch (channel) {
      case 'email':
        return prefs.email;
      case 'sms':
        return prefs.sms;
      case 'webhook':
        return prefs.webhook;
      default:
        return undefined;
    }
  }

  /**
   * Delete preferences for a user (resets to defaults on next access).
   */
  deletePreferences(userId: string): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) {
      return false;
    }
    this.repository.delete(prefs.id);
    this.logger.info(`Deleted preferences for user: ${userId}`);
    return true;
  }
}

