describe('NotificationService with preferences', () => {
  let db: Database;
  let preferencesRepository: PreferencesRepository;
  let preferencesService: PreferencesService;
  let eventBus: EventBus;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    preferencesRepository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepository);
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    notificationService = new NotificationService(eventBus, [], preferencesService);
  });

  it('should send notifications when user has no preferences', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notifications when user has email disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notifications for unsubscribed categories', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      categories: { account_updated: false },
    });

    const event: UserUpdatedEvent = {
      type: 'user:updated',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      changes: ['name'],
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should still send subscribed categories while others are unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      categories: { account_updated: false },
    });

    // This should be sent (order_confirmation is still subscribed)
    const orderEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    // This should be suppressed (account_updated is unsubscribed)
    const updateEvent: UserUpdatedEvent = {
      type: 'user:updated',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      changes: ['email'],
      timestamp: new Date(),
    };

    await eventBus.emit(orderEvent);
    await eventBus.emit(updateEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.subject).toContain('Order Confirmation');
  });

  it('should work without preferences service (backward compatible)', async () => {
    const serviceWithoutPrefs = new NotificationService(eventBus);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // Two notifications: one from notificationService (with prefs), one from serviceWithoutPrefs
    // But we're checking serviceWithoutPrefs specifically
    expect(serviceWithoutPrefs.getNotificationCount()).toBe(1);
  });

  it('should suppress SMS notifications when SMS is disabled by default', async () => {
    // Create a mock SMS adapter
    const smsAdapter: NotificationAdapter = {
      channel: 'sms',
      async send(payload: NotificationPayload): Promise<NotificationResult> {
        return { success: true, channel: 'sms', deliveredAt: new Date() };
      },
    };

    const smsService = new NotificationService(eventBus, [smsAdapter], preferencesService);

    // User has default preferences (SMS disabled by default)
    preferencesService.getOrCreatePreferences('user-1');

    // Manually dispatch an SMS notification by emitting an event that triggers dispatch
    // Since default handlers only dispatch to email, we verify through the preferences check
    // by checking shouldSend directly
    expect(preferencesService.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(false);
  });

  it('should allow SMS notifications when SMS is explicitly enabled', async () => {
    preferencesService.updateSmsPreferences('user-1', {
      enabled: true,
      phoneNumber: '+15551234567',
    });

    expect(preferencesService.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(true);
    expect(preferencesService.shouldSend('user-1', 'sms', 'welcome')).toBe(true);
  });

  it('should check preferences independently per channel', async () => {
    // Disable email, enable SMS
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    preferencesService.updateSmsPreferences('user-1', { enabled: true });

    // Email should be suppressed
    expect(preferencesService.shouldSend('user-1', 'email', 'order_confirmation')).toBe(false);
    // SMS should be allowed
    expect(preferencesService.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(true);
  });
});

